-- 20251229000000_add_contractors.sql
-- Add contractors table and update work_orders for contractor relationships

-- Create ContractorStatus enum
DO $$ BEGIN
    CREATE TYPE contractorstatus AS ENUM ('ACTIVE', 'INACTIVE', 'PENDING');
EXCEPTION WHEN duplicate_object THEN null;
END $$;

-- Create contractors table
CREATE TABLE IF NOT EXISTS contractors (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    name VARCHAR(255) NOT NULL,
    phone_number VARCHAR(50) NOT NULL,
    email VARCHAR(255),
    company_name VARCHAR(255),
    specialty VARCHAR(100) NOT NULL,
    hourly_rate INTEGER,  -- Cost in cents
    status contractorstatus NOT NULL DEFAULT 'ACTIVE',
    notes TEXT,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Create indexes on contractors table
CREATE INDEX IF NOT EXISTS ix_contractors_name ON contractors(name);
CREATE INDEX IF NOT EXISTS ix_contractors_phone_number ON contractors(phone_number);
CREATE INDEX IF NOT EXISTS ix_contractors_specialty ON contractors(specialty);
CREATE INDEX IF NOT EXISTS ix_contractors_status ON contractors(status);
CREATE INDEX IF NOT EXISTS ix_contractors_created_at ON contractors(created_at);

-- Remove old contractor text fields from work_orders
ALTER TABLE work_orders DROP COLUMN IF EXISTS contractor;
ALTER TABLE work_orders DROP COLUMN IF EXISTS contractor_contact;

-- Add contractor_id foreign key to work_orders
DO $$ BEGIN
    ALTER TABLE work_orders ADD COLUMN IF NOT EXISTS contractor_id UUID;
EXCEPTION WHEN duplicate_column THEN null;
END $$;

-- Add foreign key constraint if not exists
DO $$ BEGIN
    ALTER TABLE work_orders ADD CONSTRAINT fk_work_orders_contractor_id
        FOREIGN KEY (contractor_id) REFERENCES contractors(id);
EXCEPTION WHEN duplicate_object THEN null;
END $$;

-- Create index on contractor_id
CREATE INDEX IF NOT EXISTS ix_work_orders_contractor_id ON work_orders(contractor_id);
